// Jobberman job listing links reliably follow the pattern
// https://www.jobberman.com.gh/listings/<slug>
// with the job title as the link text, so we match on that directly.
const html = $input.first().json.data;
const jobs = [];
const linkRegex = /<a[^>]+href="(https:\/\/www\.jobberman\.com\.gh\/listings\/[^"?]+)"[^>]*(?:title="([^"]+)")?[^>]*>([^<]{3,150})<\/a>/g;
let match;
const seen = new Set();

while ((match = linkRegex.exec(html)) !== null) {
  const link = match[1];
  const title = (match[2] || match[3] || '').trim();
  if (title && !seen.has(link)) {
    seen.add(link);
    jobs.push({ title, link, source: 'Jobberman' });
  }
}

return jobs.map(j => ({ json: j }));

// JobWebGhana runs on WordPress + the JobRoller plugin.
// Job links reliably follow the pattern https://jobwebghana.com/jobs/<slug>/
// with the job+company title as the link text, so we match on that pattern
// directly instead of relying on CSS classes (which are more likely to change).
const html = $input.first().json.data;
const jobs = [];
const linkRegex = /<a[^>]+href="(https:\/\/jobwebghana\.com\/jobs\/[^"]+)"[^>]*>([^<]{10,150})<\/a>/g;
let match;
const seen = new Set();

while ((match = linkRegex.exec(html)) !== null) {
  const link = match[1];
  const title = match[2].trim();
  if (title && !seen.has(link) && !/facebook|sharer|feed/i.test(link)) {
    seen.add(link);
    jobs.push({ title, link, source: 'JobWebGhana' });
  }
}

return jobs.map(j => ({ json: j }));

// Keep only IT/Software/Tech-relevant listings, and drop ones we've already emailed before.
const keywords = /developer|software|IT\b|tech|programmer|network|cyber|data|system admin|it officer|full[- ]stack|backend|frontend|devops|database|IT support/i;

const items = $input.all().map(i => i.json).filter(j => j.title && keywords.test(j.title));

// Dedup within this run
const seenLinks = new Set();
const deduped = items.filter(j => {
  if (seenLinks.has(j.link)) return false;
  seenLinks.add(j.link);
  return true;
});

// Cross-run memory: track links we've already sent using workflow static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.sentLinks) staticData.sentLinks = [];
const alreadySent = new Set(staticData.sentLinks);

const newJobs = deduped.filter(j => !alreadySent.has(j.link));

// Update memory (cap at last 500 to avoid unbounded growth)
staticData.sentLinks = [...alreadySent, ...newJobs.map(j => j.link)].slice(-500);

return newJobs.map(j => ({ json: j }));

const jobs = $input.all().map(i => i.json);
const rows = jobs.map(j => `<li><a href="${j.link}">${j.title}</a> — <em>${j.source}</em></li>`).join('\n');
const html = `<h2>Today's IT/Tech Job Listings in Ghana</h2><ul>${rows}</ul>`;
return [{ json: { emailHtml: html, jobCount: jobs.length } }];
